// typical component internals... constructor(), render(), etc.\n}\n\n// wrap component with HOC...\nexport default HotKeys(MyComponent);\n```\nYou can then use the component as normal, supplying appropriate `keyMap` and `handlers` props.\n\n```js\nconst keys = {\n  'delete' : ['delete','backspace'],\n};\n\nconst handlers = {\n  'delete': this.doDelete\n};\n\n<MyComponent keyMap={keys} handlers={handlers} />\n```--\x3e\n\n\n### Props\nName | type | description | default | required\n--- | --- | --- | --- | ---\nkeyMap | object | Object of named hotkey sequences: e.g. { 'deletion': ['delete', 'backspace'], 'leftArrow': 'left' } | |\nhandlers | object | Object of hotkey sequence names with corresponding handler functions: e.g. { 'delete': this.doDelete }| |\nnoWrapper | bool | if true, HotKeys will attempt to use its child component's outer container as its basis for focus. If false, it will wrap the component in the element with the tagname provided in the `component` prop. | false |\ncomponent | any | Tagname of component that will be potentially used to wrap the child component and keep track of focus. | 'div' |\n")]};var _BasicUsage=function _BasicUsage(){return(0,jsx_runtime.jsx)(stories_BasicUsage,{})},HotKeys_stories_CommandList=function CommandList(){return(0,jsx_runtime.jsx)(stories_CommandList,{})};HotKeys_stories_CommandList.story={name:"CommandList"},_BasicUsage.parameters=HotKeys_stories_objectSpread({storySource:{source:"() => <BasicUsage />"}},_BasicUsage.parameters),HotKeys_stories_CommandList.parameters=HotKeys_stories_objectSpread({storySource:{source:"() => <CommandListUsage />"}},HotKeys_stories_CommandList.parameters)},"./lib/Icon/stories/Icon.stories.js":(__unused_webpack_module,__webpack_exports__,__webpack_require__)=>{"use strict";__webpack_require__.r(__webpack_exports__),__webpack_require__.d(__webpack_exports__,{Label:()=>Label,Statuses:()=>Statuses,_AvailableIcons:()=>_AvailableIcons,_Contexts:()=>_Contexts,_CustomIcon:()=>_CustomIcon,_Styl